    "public final void serialize(JsonGenerator gen, SerializerProvider ctxt) throws IOException
    {
        if (_value == null) {
            ctxt.defaultSerializeNull(gen);
        } else if (_value instanceof JsonSerializable) {
            ((JsonSerializable) _value).serialize(gen, ctxt);
        } else {
            // 25-May-2018, tatu: [databind#1991] do not call via generator but through context;
            //    this to preserve contextual information
            ctxt.writeValue(gen, _value);
        }
    }"
  ],
  "additional_testcases": [
    {
      "path": "com/fasterxml/jackson/databind/node/POJONodeTest.java::testPOJONodeCustomSerInArray",
      "testcase": "public void testPOJONodeCustomSerInArray() throws Exception
    {
      Data data = new Data();
      data.aStr = "Hello";

      ArrayNode arr = MAPPER.createArrayNode();
      arr.addPOJO(data);

      final String EXP = "[{\"aStr\":\"The value is: Hello!\"}]";

      String out = MAPPER.writer().withAttribute("myAttr", "Hello!").writeValueAsString(arr);
      assertEquals(EXP, out);
    }"
    }
